+    #[test]
+    fn test_retained_count_sum_scan_skips_unused_ipk_alias_decode() {
+        let _profile_guard = StatementReuseHotPathProfileGuard::new();
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute(
+            "CREATE TABLE mem_retained_count_sum_ipk_alias \
+             (id INTEGER PRIMARY KEY, score INTEGER NOT NULL);",
+        )
+        .unwrap();
+
+        conn.execute("INSERT INTO mem_retained_count_sum_ipk_alias VALUES (1, 10);")
+            .unwrap();
+        conn.execute("INSERT INTO mem_retained_count_sum_ipk_alias VALUES (2, 20);")
+            .unwrap();
+        assert!(conn.retained_autocommit_txn.borrow().is_some());
+        assert!(
+            conn.retained_autocommit_count_sum_cache.borrow().is_none(),
+            "without prior COUNT/SUM interest, the retained scan should start from a cache miss"
+        );
+
+        let stmt = conn
+            .prepare("SELECT COUNT(*), SUM(score) FROM mem_retained_count_sum_ipk_alias;")
+            .unwrap();
+
+        reset_hot_path_profile();
+        let row = stmt.query_row().unwrap();
+        assert_eq!(
+            row.values(),
+            &[SqliteValue::Integer(2), SqliteValue::Integer(30)]
+        );
+
+        let profile = hot_path_profile_snapshot();
+        assert!(
+            profile.retained_autocommit_overlay_hits >= 1,
+            "dirty retained COUNT/SUM should use the overlay scan: {profile:?}"
+        );
+        assert_eq!(
+            profile.record_decode.decoded_values.null_count, 0,
+            "SUM(score) must not decode the unrelated INTEGER PRIMARY KEY alias slot per row: {profile:?}"
+        );
+    }
